Here's a JavaScript function that checks if an input number is prime and takes an array of five numbers as an argument, printing prime numbers to the console:

```javascript
function isPrime(num) {
  if (num < 2) return false; // Numbers below 2 are not prime
  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) return false; // If number is divisible by any number up to its square root, it's not prime
  }
  return true; // If the loop completes without finding a divisor, the number is prime
}

function checkPrimesInArray(arr) {
  for (let i = 0; i < arr.length; i++) {
    const num = arr[i];
    if (isPrime(num)) {
      console.log(num); // Print prime numbers to the console
    }
  }
}

// Example usage:
const inputArray = [1, 7, 4, 13, 11];
checkPrimesInArray(inputArray);
```

The `isPrime` function checks whether a given number is prime by testing divisibility against numbers up to its square root. The `checkPrimesInArray` function iterates through the input array and calls `isPrime` for each number, printing prime numbers to the console when they're found.

